import { auth } from "@/lib/auth";
import { redirect } from "next/navigation";
import { prisma } from "@/lib/db";
import { PageHeader } from "@/components/layout/PageHeader";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faChartBar } from "@fortawesome/free-solid-svg-icons";
import { ExportStatsButton } from "@/components/stats/ExportStatsButton";

export const metadata = { title: "Stats" };

function fmtAvg(val: number | null | undefined): string {
  if (val == null) return "—";
  return val.toFixed(3).replace(/^0/, "");
}

function fmtStat(val: number | null | undefined): string {
  if (val == null) return "—";
  return val.toString();
}

export default async function StatsPage() {
  const session = await auth();
  if (!session?.user?.id) redirect("/login");
  const userId = session.user.id;

  const team = await prisma.team.findFirst({
    where: { userId },
    include: {
      seasons: {
        where: { isActive: true },
        include: {
          teamStats: true,
          playerStats: {
            include: {
              player: {
                select: {
                  firstName: true, lastName: true, jerseyNumber: true, isActive: true,
                },
              },
            },
            orderBy: { battingAvg: "desc" },
          },
        },
      },
    },
  });

  if (!team) redirect("/login");

  const activeSeason  = team.seasons[0];
  const teamStats     = activeSeason?.teamStats;
  const playerStats   = activeSeason?.playerStats ?? [];
  const hasStats      = playerStats.some((p) => p.gamesPlayed > 0);

  const teamColor = team.teamColor ?? "#00e87a";

  return (
    <div>
      <PageHeader
        eyebrow={activeSeason?.name ?? "Season"}
        title="Stats"
        subtitle={
          hasStats
            ? `${playerStats.length} players · ${teamStats?.wins ?? 0}W – ${teamStats?.losses ?? 0}L`
            : "No stats recorded yet"
        }
      />

      {/* Team summary strip */}
      {teamStats && (
        <div className="mb-6 grid grid-cols-2 gap-4 md:grid-cols-4">
          {[
            { label: "Wins",         value: teamStats.wins,        color: teamColor },
            { label: "Losses",       value: teamStats.losses,      color: "#ff3d3d" },
            { label: "Runs Scored",  value: teamStats.runsScored,  color: teamColor },
            { label: "Runs Allowed", value: teamStats.runsAllowed, color: "#94a3b8" },
          ].map((s) => (
            <div key={s.label} className="card py-4 text-center">
              <div style={{
                fontFamily: "var(--font-display)", fontSize: "2.25rem",
                fontWeight: 900, color: s.color, lineHeight: 1,
              }}>
                {s.value}
              </div>
              <div style={{
                fontFamily: "var(--font-body)", fontSize: "0.7rem", fontWeight: 700,
                letterSpacing: "0.12em", textTransform: "uppercase",
                color: "var(--color-text-muted)", marginTop: 4,
              }}>
                {s.label}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Empty state */}
      {!hasStats && (
        <div className="card flex flex-col items-center gap-3 py-16 text-center">
          <FontAwesomeIcon icon={faChartBar}
            style={{ width: 32, height: 32, color: "var(--color-text-muted)" }} />
          <p style={{ color: "var(--color-text-muted)", margin: 0 }}>
            Stats will appear here once you finish a game in the scorebook.
          </p>
        </div>
      )}

      {/* Player stats table */}
      {hasStats && (
        <div className="card overflow-x-auto p-0">
          <table style={{ width: "100%", borderCollapse: "collapse", minWidth: 700 }}>
            <thead>
              <tr style={{
                borderBottom: "1px solid var(--color-border-subtle)",
                background: "rgba(255,255,255,0.02)",
              }}>
                {[
                  { label: "#",   align: "center" },
                  { label: "Player", align: "left" },
                  { label: "G",   align: "center" },
                  { label: "AB",  align: "center" },
                  { label: "H",   align: "center" },
                  { label: "2B",  align: "center" },
                  { label: "3B",  align: "center" },
                  { label: "HR",  align: "center" },
                  { label: "RBI", align: "center" },
                  { label: "R",   align: "center" },
                  { label: "BB",  align: "center" },
                  { label: "AVG", align: "center" },
                  { label: "OBP", align: "center" },
                  { label: "SLG", align: "center" },
                  { label: "OPS", align: "center" },
                ].map((h) => (
                  <th
                    key={h.label}
                    className="px-3 py-3"
                    style={{
                      fontFamily: "var(--font-body)",
                      fontSize: "0.6875rem",
                      fontWeight: 700,
                      letterSpacing: "0.1em",
                      textTransform: "uppercase",
                      color: "rgba(238,238,245,0.4)",
                      textAlign: h.align as "center" | "left",
                      whiteSpace: "nowrap",
                    }}
                  >
                    {h.label}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {playerStats.map((ps) => {
                const name = `${ps.player.firstName} ${ps.player.lastName}`;
                const isLeader = ps.battingAvg === playerStats[0]?.battingAvg && ps.battingAvg !== null;
                return (
                  <tr
                    key={ps.id}
                    style={{
                      borderBottom: "1px solid var(--color-border-subtle)",
                      opacity: ps.player.isActive ? 1 : 0.5,
                    }}
                  >
                    {/* Jersey # */}
                    <td className="px-3 py-3" style={{ textAlign: "center",
                      fontFamily: "var(--font-mono)", fontSize: "0.8rem",
                      color: "var(--color-text-muted)" }}>
                      {ps.player.jerseyNumber ?? "—"}
                    </td>

                    {/* Name */}
                    <td className="px-3 py-3" style={{ whiteSpace: "nowrap" }}>
                      <span style={{
                        fontFamily: "var(--font-display)", fontWeight: 700,
                        fontSize: "0.9rem", color: "#eeeef5",
                      }}>
                        {name}
                      </span>
                    </td>

                    {/* Counting stats */}
                    {[
                      ps.gamesPlayed,
                      ps.atBats,
                      ps.hits,
                      ps.doubles,
                      ps.triples,
                      ps.homeRuns,
                      ps.rbi,
                      ps.runs,
                      ps.walks,
                    ].map((val, i) => (
                      <td key={i} className="px-3 py-3" style={{
                        textAlign: "center",
                        fontFamily: "var(--font-mono)", fontSize: "0.85rem",
                        color: "var(--color-text-secondary)",
                      }}>
                        {fmtStat(val)}
                      </td>
                    ))}

                    {/* Rate stats */}
                    <td className="px-3 py-3" style={{ textAlign: "center",
                      fontFamily: "var(--font-mono)", fontSize: "0.85rem",
                      fontWeight: isLeader ? 700 : 400,
                      color: isLeader ? teamColor : "var(--color-text-secondary)" }}>
                      {fmtAvg(ps.battingAvg)}
                    </td>
                    <td className="px-3 py-3" style={{ textAlign: "center",
                      fontFamily: "var(--font-mono)", fontSize: "0.85rem",
                      color: "var(--color-text-secondary)" }}>
                      {fmtAvg(ps.obp)}
                    </td>
                    <td className="px-3 py-3" style={{ textAlign: "center",
                      fontFamily: "var(--font-mono)", fontSize: "0.85rem",
                      color: "var(--color-text-secondary)" }}>
                      {fmtAvg(ps.slugging)}
                    </td>
                    <td className="px-3 py-3" style={{ textAlign: "center",
                      fontFamily: "var(--font-mono)", fontSize: "0.85rem",
                      color: "var(--color-text-secondary)" }}>
                      {ps.ops != null ? ps.ops.toFixed(3) : "—"}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
